import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.8tqBsFWt.js";const x=JSON.parse('{"title":"Context Packets","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"developers/context.md","filePath":"developers/context.md","lastUpdated":1776274509000}'),d={name:"developers/context.md"};function i(r,t,c,s,h,l){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="context-packets" tabindex="-1">Context Packets <a class="header-anchor" href="#context-packets" aria-label="Permalink to &quot;Context Packets&quot;">​</a></h1><p>Plugin Channel Identifier: <code>openboatutils:context</code></p><p>Contexts come in three flavours:</p><ul><li>Default Context, activated by any <code>openboatutils:settings</code> packet and resets to vannila whenever it is switched to.</li><li>Stored Context, a named persistent context that can be dynamically switched to that stores any settings sent to it.</li><li>Entity Context, applies to a specific entity uuid, overriding any other contexts that could be active.</li></ul><p>By default openboatutils has no context active (<em><strong><code>null</code> context</strong></em>), which effectively disables every internal hook used, sending a reset packet to the default context will switch to the <code>null</code> context as a safeguard.</p><p>The default context behaves identically to pre-context versions of openboatutils.</p><h2 id="clientbound" tabindex="-1">Clientbound <a class="header-anchor" href="#clientbound" aria-label="Permalink to &quot;Clientbound&quot;">​</a></h2><h3 id="reset-context" tabindex="-1">Reset Context <a class="header-anchor" href="#reset-context" aria-label="Permalink to &quot;Reset Context&quot;">​</a></h3><p>Resets the currently active context back to <code>null</code>.</p><p>This effectively disables openboatutils and returns behavior to vanilla.</p><table tabindex="0"><thead><tr><th>Packet ID</th></tr></thead><tbody><tr><td>0 (<code>short</code>)</td></tr></tbody></table><hr><h3 id="switch-context" tabindex="-1">Switch Context <a class="header-anchor" href="#switch-context" aria-label="Permalink to &quot;Switch Context&quot;">​</a></h3><p>Switches the active context to a stored context identified by its Identifier.</p><p>If the identifier belongs to the <code>openboatutils</code> namespace, only the <code>default</code> context is allowed, the rest are reserved for future use.</p><table tabindex="0"><thead><tr><th>Packet ID</th><th>Identifier</th></tr></thead><tbody><tr><td>1 (<code>short</code>)</td><td><code>string (namespaced:key)</code></td></tr></tbody></table><hr><h3 id="drop-context" tabindex="-1">Drop Context <a class="header-anchor" href="#drop-context" aria-label="Permalink to &quot;Drop Context&quot;">​</a></h3><p>Removes a stored context from the client.</p><p>If the removed context is currently active, the active context is also reset to <code>null</code>.</p><table tabindex="0"><thead><tr><th>Packet ID</th><th>Identifier</th></tr></thead><tbody><tr><td>2 (<code>short</code>)</td><td><code>string (namespaced:key)</code></td></tr></tbody></table><hr><h3 id="store-context" tabindex="-1">Store Context <a class="header-anchor" href="#store-context" aria-label="Permalink to &quot;Store Context&quot;">​</a></h3><p>Creates or overwrites a stored context with the given identifier, and applies a batch of settings to it.</p><p>The settings are read as a <a href="/developers/settings.html#transaction">Transaction</a> minus the transaction packet id <code>short</code>. You can write this by writing a transaction packet&#39;s payload after the identifier.</p><table tabindex="0"><thead><tr><th>Packet ID</th><th>Identifier</th><th>Settings</th></tr></thead><tbody><tr><td>3 (<code>short</code>)</td><td><code>string (namespaced:key)</code></td><td><code>transaction</code></td></tr></tbody></table><hr><h3 id="entity-context" tabindex="-1">Entity Context <a class="header-anchor" href="#entity-context" aria-label="Permalink to &quot;Entity Context&quot;">​</a></h3><p>Creates or updates a context tied to a specific entity (by UUID).</p><p>Like <code>Store Context</code>, the settings are read as a <a href="/developers/settings.html#transaction">Transaction</a> minus the transaction packet id <code>short</code>. You can write this by writing a transaction packet&#39;s payload after the identifier.</p><table tabindex="0"><thead><tr><th>Packet ID</th><th>Entity UUID</th><th>Settings</th></tr></thead><tbody><tr><td>4 (<code>short</code>)</td><td><code>string (UUID with dashes)</code></td><td><code>transaction</code></td></tr></tbody></table>',31)])])}const b=e(d,[["render",i]]);export{x as __pageData,b as default};
